import React, { useEffect } from 'react';
import { Calendar, type CalendarProps } from 'primereact/calendar';
import type { IKitsInputCalendar } from '@lmb-it/kitsconcerto-types';
import KitsContainer from '../../helpers/FormContainer';
import {useFormInputController} from '../../helpers/useFormInputController';
import { useLanguage, useComponentDefaults, useResolvedStyle } from "../../../hooks";
import { useKitsTheme } from "../../../contexts/Theme";
import Addons from '../../helpers/Addons';

const KitsInputCalendar = <T = CalendarProps,>({ ref, ...rawProps }: IKitsInputCalendar<T>) => {
    const { mergedProps: props, themeStyle, elementStyles } = useComponentDefaults('Datepicker', rawProps as any, 'Input');
    const resolvedThemeStyle = useResolvedStyle(themeStyle);
    const resolvedRootStyle = useResolvedStyle(elementStyles?.root || {});

    const {
        id, label, rightAddon, leftAddon,
        helperText, errors, invalid, required, hideError,
        isFloatedLabel, disabled, inputSize,
        localProps = {} as CalendarProps,
        defaultValue, value, onChange,
        attached,
        containerStyle,
        ...rest
    } = props as any;

    const { currentLanguage } = useLanguage();
    const { resolveToken } = useKitsTheme();
    const primaryColor = resolveToken('primary');
    const { value: internalVal, emitChange } = useFormInputController<Date | Date[] | null>({
        value,
        defaultValue,
        onChange: (event) => {
            onChange?.(event.target.value)
        },
    });

    useEffect(() => {
        // ensure internal state updates when controlled value changes
    }, [value]);

    const Element =  <Calendar
        ref={ref as any}
        value={internalVal as any}
        onChange={(e) => emitChange(e.value as any)}
        locale={currentLanguage}
        disabled={disabled}
        className="w-full"
        inputStyle={{ borderRadius: 0, border:'none', ...(resolvedRootStyle || resolvedThemeStyle) }}
        pt={{
            day: ({ context }: any) => context?.selected ? {
                style: { backgroundColor: primaryColor, color: 'white', borderRadius: '50%' },
            } : context?.today ? {
                style: { color: primaryColor, fontWeight: 'bold' },
            } : undefined,
            previousButton: { style: { color: primaryColor } },
            nextButton: { style: { color: primaryColor } },
        }}
        {...localProps}
    />

    if (attached) {
        return Element;
    }

    return (
        <KitsContainer
            id={id}
            disabled={disabled}
            helperText={helperText}
            errors={errors}
            invalid={invalid}
            label={label}
            required={required}
            rightAddon={rightAddon}
            leftAddon={leftAddon}
            hideError={hideError}
            isFloatedLabel={isFloatedLabel}
            inputSize={inputSize}
            containerStyle={containerStyle}
            elementStyles={elementStyles}
        >
            {Element}
        </KitsContainer>
    );
};

export default KitsInputCalendar;
